import { useState, useEffect } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [zoom, setZoom] = useState(false);
  const [animatedScore, setAnimatedScore] = useState(0);
  const [downloading, setDownloading] = useState(false);
  const [darkMode, setDarkMode] = useState(true); // Toggle state

  const claimId = `CLM-${Date.now()}`;

  /* ---------------- Fraud Score Animation ---------------- */
  useEffect(() => {
    if (result) {
      let start = 0;
      const end = result.fraud_confidence_score || 0;
      const duration = 1200;
      const stepTime = 20;
      const step = (end - start) / (duration / stepTime);

      const interval = setInterval(() => {
        start += step;
        if (start >= end) {
          start = end;
          clearInterval(interval);
        }
        setAnimatedScore(Math.round(start));
      }, stepTime);
    }
  }, [result]);

  /* ---------------- Helper Functions ---------------- */
  const riskLevel = (score) => {
    if (score <= 40) return "Low Risk";
    if (score <= 75) return "Medium Risk";
    return "High Risk";
  };

  const gaugeColor = (score) => (score <= 50 ? "#00ff9c" : score <= 80 ? "#ffea00" : "#ff3d00");
  const verdictColor = (verdict) => {
    if (!verdict) return "#aaa";
    if (verdict.toLowerCase() === "fraud") return "#ff3d00";
    if (verdict.toLowerCase() === "suspicious") return "#ffea00";
    return "#00ff9c";
  };

  /* ---------------- File Handling ---------------- */
  const handleFileChange = (e) => {
    setError(null);
    const selected = e.target.files[0];
    if (!selected) return;
    setFile(selected);
    setPreview(URL.createObjectURL(selected));
    setResult(null);
    setAnimatedScore(0);
  };

  const handleUpload = async () => {
    if (!file) return setError("Please select an image first.");
    const formData = new FormData();
    formData.append("file", file);
    setLoading(true);
    setResult(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", { method: "POST", body: formData });
      if (!response.ok) throw new Error("Server error");
      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message || "Something went wrong!");
    }
    setLoading(false);
  };

  const handleReset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
    setZoom(false);
    setAnimatedScore(0);
    setDownloading(false);
  };

  const toggleMode = () => setDarkMode(!darkMode); // Toggle function

  /* ---------------- Download Report ---------------- */
  const downloadReport = () => {
    if (!result) return;
    setDownloading(true);

    const htmlContent = `
      <html>
        <head>
          <title>Audit Report - ${claimId}</title>
          <style>
            body { font-family: Arial, sans-serif; padding: 20px; background: ${
              darkMode ? "#1a1a2e" : "#f3f6fb"
            }; color: ${darkMode ? "#fff" : "#333"}; }
            h1,h2,h3 { color: ${darkMode ? "#00ff9c" : "#1e40af"}; }
            .meta { font-size: 14px; color: ${darkMode ? "#ccc" : "#555"}; margin-bottom: 20px; }
            .stats { display: flex; flex-wrap: wrap; gap: 20px; margin-bottom: 30px; }
            .statBox { flex: 1 1 180px; background: ${
              darkMode ? "rgba(255,255,255,0.05)" : "#f4f7fa"
            }; padding: 15px; border-radius: 8px; text-align: center; }
            pre { background: ${darkMode ? "rgba(255,255,255,0.05)" : "#f1f5f9"}; padding: 10px; border-radius: 6px; overflow-x: auto; color: ${
              darkMode ? "#fff" : "#333"
            };}
            .green { color: #16a34a; font-weight: bold; }
            .yellow { color: #f59e0b; font-weight: bold; }
            .red { color: #dc2626; font-weight: bold; }
          </style>
        </head>
        <body>
          <h1>ClaimPilot AI Audit Report</h1>
          <p class="meta">Claim ID: <strong>${claimId}</strong><br/>Date: ${new Date().toLocaleString()}</p>
          <div class="stats">
            <div class="statBox"><h3>Total Estimate</h3><p>PKR ${result.total_estimate_pkr}</p></div>
            <div class="statBox"><h3>Fraud Score</h3><p class="${
              result.fraud_confidence_score <= 50 ? "green" : result.fraud_confidence_score <= 80 ? "yellow" : "red"
            }">${result.fraud_confidence_score}%</p></div>
            <div class="statBox"><h3>Verdict</h3><p class="${
              result.verdict.toLowerCase() === "fraud" ? "red" : result.verdict.toLowerCase() === "suspicious" ? "yellow" : "green"
            }">${result.verdict}</p></div>
            <div class="statBox"><h3>Damaged Parts</h3><p>${result.damaged_parts?.length || 0}</p></div>
          </div>
          <h2>Fraud Analysis</h2>
          <p>${result.fraud_analysis || "No fraud detected."}</p>
          <h2>Itemized Costs</h2>
          <pre>${JSON.stringify(result.itemized_costs,null,2)}</pre>
        </body>
      </html>
    `;

    const blob = new Blob([htmlContent], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `audit_report_${claimId}.html`;
    a.click();
    URL.revokeObjectURL(url);

    setTimeout(() => setDownloading(false), 800);
  };

  /* ---------------- Styles ---------------- */
  const theme = darkMode
    ? {
        page: { minHeight: "100vh", background: "linear-gradient(135deg,#0f0c29,#302b63,#24243e)", fontFamily: "Poppins, sans-serif", padding: 30, color: "#fff" },
        container: { maxWidth: 1000, margin: "auto" },
        header: { textAlign: "center", marginBottom: 50 },
        logo: { fontSize: 42, fontWeight: 800, background: "linear-gradient(90deg,#00ff9c,#00f0ff)", WebkitBackgroundClip: "text", color: "transparent" },
        tagline: { marginTop: 10, color: "#aaa", fontSize: 16 },
        uploadCard: { background: "rgba(255,255,255,0.05)", padding: 35, borderRadius: 20, border: "1px solid rgba(255,255,255,0.1)", backdropFilter: "blur(12px)", boxShadow: "0 20px 50px rgba(0,0,0,0.3)", marginBottom: 40 },
        uploadLabel: { display: "block", border: "2px dashed #00ff9c", padding: 30, borderRadius: 15, textAlign: "center", fontWeight: 600, cursor: "pointer", marginBottom: 25, transition: "0.3s all", color: "#fff" },
        preview: { width: "100%", maxHeight: 320, borderRadius: 15, marginBottom: 15, cursor: "zoom-in", objectFit: "cover", boxShadow: "0 0 25px rgba(0,255,156,0.4)" },
        previewZoom: { width: "100%", maxHeight: 600, borderRadius: 15, marginBottom: 15, cursor: "zoom-out", objectFit: "contain", boxShadow: "0 0 35px rgba(0,255,156,0.6)" },
        buttonRow: { display: "flex", gap: 15, justifyContent: "center", flexWrap: "wrap" },
        primaryBtn: { padding: "14px 32px", background: "linear-gradient(90deg,#00ff9c,#00f0ff)", borderRadius: 12, border: "none", fontWeight: 700, cursor: "pointer", color: "#000", boxShadow: "0 5px 20px rgba(0,255,156,0.5)", transition: "0.3s all" },
        resetBtn: { padding: "14px 32px", background: "#ff3d00", borderRadius: 12, border: "none", fontWeight: 700, cursor: "pointer", color: "#fff", boxShadow: "0 5px 20px rgba(255,61,0,0.5)", transition: "0.3s all" },
        disabledBtn: { padding: "14px 32px", background: "#555", borderRadius: 12, border: "none", color: "#ccc" },
        resultCard: { background: "rgba(255,255,255,0.05)", borderRadius: 20, padding: 35, boxShadow: "0 20px 50px rgba(0,0,0,0.3)", backdropFilter: "blur(15px)", marginTop: 20 },
        meta: { fontSize: 13, color: "#aaa" },
        stats: { display: "flex", flexWrap: "wrap", gap: 20, margin: "30px 0" },
        statBox: { flex: "1 1 180px", padding: 20, borderRadius: 15, background: "rgba(255,255,255,0.05)", textAlign: "center", boxShadow: "0 8px 20px rgba(0,255,156,0.2)", transition: "0.3s transform", cursor: "default" },
        gauge: { width: 90, height: 90 },
        gaugeText: { fontSize: 10, fontWeight: 700, fill: "#fff", textAnchor: "middle" },
        progressBar: { height: 14, background: "#111", borderRadius: 12, overflow: "hidden", marginBottom: 20 },
        progressFill: { height: "100%", background: "linear-gradient(90deg,#00ff9c,#ffea00,#ff3d00)", transition: "width 1s ease" },
        partItem: { display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid rgba(255,255,255,0.1)" },
        severity: { background: "#ff3d0033", color: "#ff3d00", padding: "3px 10px", borderRadius: 8, fontWeight: 600 },
        pre: { background: "rgba(255,255,255,0.05)", padding: 20, borderRadius: 12, overflowX: "auto", color: "#fff" },
        downloadBtn: { marginTop: 25, padding: "14px 32px", background: "linear-gradient(90deg,#00ff9c,#00f0ff)", border: "none", borderRadius: 12, fontWeight: 700, cursor: "pointer", color: "#000", boxShadow: "0 5px 20px rgba(0,255,156,0.5)", transition: "0.3s all" },
        error: { color: "#ff3d00", marginTop: 10 },
      }
    : {
        // Light mode styles
        page: { minHeight: "100vh", background: "#f3f6fb", fontFamily: "Segoe UI, sans-serif", padding: 30, color: "#111" },
        container: { maxWidth: 1000, margin: "auto" },
        header: { textAlign: "center", marginBottom: 40 },
        logo: { fontSize: 38, fontWeight: 700 },
        tagline: { color: "#555" },
        status: { marginTop: 10, color: "#16a34a", fontSize: 13 },
        dot: { height: 8, width: 8, background: "#16a34a", borderRadius: "50%", display: "inline-block", marginRight: 6 },
        uploadCard: { background: "#fff", padding: 30, borderRadius: 16, boxShadow: "0 10px 25px rgba(0,0,0,0.05)", marginBottom: 40 },
        uploadLabel: { display: "block", border: "2px dashed #ccc", padding: 20, borderRadius: 12, cursor: "pointer", marginBottom: 20, textAlign: "center" },
        preview: { width: "100%", maxHeight: 300, objectFit: "cover", borderRadius: 12, marginBottom: 15, cursor: "zoom-in" },
        previewZoom: { width: "100%", maxHeight: 600, objectFit: "contain", borderRadius: 12, marginBottom: 15, cursor: "zoom-out" },
        buttonRow: { display: "flex", gap: 10, justifyContent: "center" },
        primaryBtn: { padding: "12px 25px", background: "#1e40af", color: "#fff", border: "none", borderRadius: 8, cursor: "pointer" },
        resetBtn: { padding: "12px 25px", background: "#dc2626", color: "#fff", border: "none", borderRadius: 8, cursor: "pointer" },
        disabledBtn: { padding: "12px 25px", background: "#aaa", color: "#fff", border: "none", borderRadius: 8 },
        resultCard: { background: "#fff", padding: 30, borderRadius: 16, boxShadow: "0 10px 25px rgba(0,0,0,0.05)" },
        meta: { fontSize: 13, color: "#666" },
        stats: { display: "flex", flexWrap: "wrap", gap: 20, margin: "30px 0" },
        statBox: { flex: "1 1 180px", background: "#f4f7fa", padding: 20, borderRadius: 12, textAlign: "center" },
        gauge: { width: 90, height: 90 },
        gaugeText: { fontSize: "0.6em", textAnchor: "middle", fill: "#1e40af" },
        progressBar: { height: 10, background: "#eee", borderRadius: 10, marginBottom: 15, overflow: "hidden" },
        progressFill: { height: "100%", background: "linear-gradient(90deg,#16a34a,#f59e0b,#dc2626)", transition: "width 1s ease" },
        partItem: { display: "flex", justifyContent: "space-between", padding: "8px 0", borderBottom: "1px solid #eee" },
        severity: { background: "#fee2e2", color: "#991b1b", padding: "2px 8px", borderRadius: 6, fontSize: 12 },
        pre: { background: "#f1f5f9", padding: 15, borderRadius: 8, overflowX: "auto" },
        downloadBtn: { marginTop: 20, padding: "12px 25px", background: "#16a34a", color: "#fff", border: "none", borderRadius: 8, cursor: "pointer" },
        error: { color: "#dc2626", marginTop: 10 },
      };

  return (
    <div style={theme.page}>
      <div style={theme.container}>
        <header style={theme.header}>
          <h1 style={theme.logo}>ClaimPilot AI</h1>
          <p style={theme.tagline}>Intelligent Vehicle Damage Assessment & Fraud Detection</p>
          <button onClick={toggleMode} style={theme.primaryBtn}>
            Toggle {darkMode ? "Light" : "Dark"} Mode
          </button>
          {result && (
            <button style={theme.downloadBtn} onClick={downloadReport} disabled={downloading}>
              {downloading ? "Preparing Report..." : "Download Audit Report"}
            </button>
          )}
        </header>

        {/* Upload Card */}
        <div
          style={theme.uploadCard}
          onDragOver={(e) => e.preventDefault()}
          onDrop={(e) => handleFileChange({ target: { files: [e.dataTransfer.files[0]] } })}
        >
          {preview && <img src={preview} alt="preview" style={zoom ? theme.previewZoom : theme.preview} onClick={() => setZoom(!zoom)} />}
          <label style={theme.uploadLabel}>
            {file ? file.name : "Click or Drag Image Here"}
            <input type="file" accept="image/*" style={{ display: "none" }} onChange={handleFileChange} />
          </label>

          <div style={theme.buttonRow}>
            <button style={theme.primaryBtn} onClick={handleUpload} disabled={loading || !file}>
              {loading ? "Analyzing..." : "Start Audit"}
            </button>
            <button style={theme.resetBtn} onClick={handleReset}>
              Reset
            </button>
          </div>
          {error && <p style={theme.error}>{error}</p>}
        </div>

        {/* Result Card */}
        {result && (
          <div style={theme.resultCard}>
            <p style={theme.meta}>
              Claim ID: <strong>{claimId}</strong> | Date: {new Date().toLocaleString()}
            </p>

            <div style={theme.stats}>
              <div style={theme.statBox}>
                <h3>Total Estimate</h3>
                <p>PKR {result.total_estimate_pkr}</p>
              </div>
              <div style={theme.statBox}>
                <h3>Fraud Score</h3>
                <p style={{ color: gaugeColor(animatedScore), fontWeight: "bold", fontSize: 20 }}>{animatedScore}%</p>
                <small>{riskLevel(animatedScore)}</small>
              </div>
              <div style={theme.statBox}>
                <h3>Verdict</h3>
                <p style={{ color: verdictColor(result.verdict), fontWeight: "bold" }}>{result.verdict}</p>
              </div>
              <div style={theme.statBox}>
                <h3>Damaged Parts</h3>
                <p>{result.damaged_parts?.length || 0}</p>
              </div>
            </div>

            <h3>Fraud Analysis</h3>
            <p>{result.fraud_analysis || "No fraud detected."}</p>

            <h3>Itemized Costs</h3>
            <pre style={theme.pre}>{JSON.stringify(result.itemized_costs, null, 2)}</pre>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
